import requests
from xml.etree import ElementTree as ET

base_url = "http://192.168.5.0:8080/geoserver/gwc/service/kml/sf:archsites"
visited = set()
pattern = "FLAG{"

def fetch(path):
    if path in visited:
        return None
    visited.add(path)
    url = f"{base_url}/{path}"
    resp = requests.get(url, timeout=10)
    if resp.status_code != 200:
        return None
    return resp.text


def process(path, depth=0):
    text = fetch(path)
    if not text:
        return False
    if pattern in text:
        print('FOUND', path)
        print(text)
        return True
    try:
        root = ET.fromstring(text)
    except ET.ParseError:
        return False
    ns = {"kml": "http://www.opengis.net/kml/2.2"}
    for placemark in root.findall('.//kml:Placemark', ns):
        desc = ET.tostring(placemark, encoding='unicode')
        if pattern in desc:
            print('PLACEMARK FOUND', path)
            print(desc)
            return True
    if depth >= 20:
        return False
    for link in root.findall('.//kml:Link', ns):
        href = link.find('kml:href', ns)
        if href is None or not href.text:
            continue
        child = href.text.split('/')[-1]
        if process(child, depth + 1):
            return True
    return False

if not process('x108y191z8.png.kml'):
    print('No flag found in KML hierarchy')
